**Solution to Follow Up Question:**

```
#include<bits/stdc++.h>
using namespace std;

#define LL long long
#define MOD 1000000007
#define fastio ios_base::sync_with_stdio(0);cin.tie(0);cout.tie(0)
#define print(a, n) for(auto _=0; _<n; _++) cout<<a[_]<<" "; cout<<"\n"
#define prints(a) for(auto _: a) cout<<_<<" "; cout<<"\n"
#define read(a, n) for(auto _=0; _<n; _++) cin>>a[_]

// Y = -7 -2 -1 -1
// X = 1 2 2 2 3 5

// Squared sorted X + Y: 1 1 1 4 4 4 4 9 25 49

int binarySearch(int pivot, int k, int n, vector<int>& nums) {
	int low = pivot-1, high = n;

	// Ex: K = 8;
	while (low <= high) {
		int partitionX = (low + high)/2; // (4+10)/2 = 7 | (7+10)/2 = 8

		if (partitionX + 1 < k) {
			low = partitionX;
			continue;
		}

		int partitionY = (partitionX+1 - k); // (7+1 - 8) = 0 | (8+1 - 8) = 1

		int LeftX = partitionX >= pivot ? nums[partitionX] : INT_MIN; // 2 | 3
		int RightX = partitionX+1 < n ? nums[partitionX+1] : INT_MAX; // 3 | 5

		int LeftY = partitionY > 0 ? -nums[partitionY-1] : INT_MAX; // INT_MAX | 7
		int RightY = partitionY < pivot ? -nums[partitionY] : INT_MIN; // 7 | 2

		if (LeftX <= LeftY && RightY <= RightX) // 2 < INT_MAX && 7 < 3 => false | 3 < 7 && 2 < 5 => true
			return max(LeftX*LeftX, RightY*RightY); // max(3*3, 2*2) => 9

		if (LeftX > LeftY) // 2 > INT_MAX => false
			high = partitionX;
		else
			low = partitionX; // low = 7
	}

	return -1;
}

int lb(int target, vector<int>& nums) {
	int low = 0, high = nums.size();
	while (low < high) {
		int mid = low + (high - low)/2;
		if (nums[mid] < target)
			low = mid + 1;
		else
			high = mid;
	}

	return low;
}

int solve(vector<int> nums, int k) {
	int n = nums.size();
	int pivot = lb(0, nums);

	if (pivot == n) // all negative numbers
		return nums[n-k]*nums[n-k];
	else if (pivot == 0) // all positive numbers
		return nums[k-1]*nums[k-1];
	else
		return binarySearch(pivot, k, n, nums);
}

int main()
{
	fastio;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 1)<<endl;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 2)<<endl;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 3)<<endl;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 4)<<endl;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 5)<<endl;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 6)<<endl;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 7)<<endl;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 8)<<endl;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 9)<<endl;
	cout<<solve({-7, -2, -1, -1, 1, 2, 2, 2, 3, 5}, 10)<<endl;

	cout<<solve({-7, -2, -1, -1, 2, 2, 2, 2, 3, 5}, 1)<<endl;
	cout<<solve({-7, -2, -1, -1, 2, 2, 2, 2, 3, 5}, 2)<<endl;

	cout<<solve({-5, -4, -3, -2, 10, 20, 30}, 2)<<endl;
	cout<<solve({-5, -4, -3, -2, 10, 20, 30}, 3)<<endl;
	cout<<solve({-5, -4, -3, -2, 10, 20, 30}, 6)<<endl;

	cout<<solve({-7, -2, -1, -1}, 2)<<endl;
	cout<<solve({-7, -2, -1, -1}, 3)<<endl;

	cout<<solve({1, 2, 2, 2, 3, 5}, 2)<<endl;
	cout<<solve({1, 2, 2, 2, 3, 5}, 4)<<endl;
	cout<<solve({1, 2, 2, 2, 3, 5}, 6)<<endl;
	exit(0);
}
```

For the PhoneScreen round:
1. Main problem - Sorting the array basis on the squared value. Key idea - We know that post squaring every element will become +ve, so only thing that matters is the magnitude of an element. We cannot be sure of the `minimum` squared value as it can be lying anywhere but we can be sure of the `max` value as it can either be at `start` or `end`.
Here's the JS code for the same -
```javaScript
var sortedSquares = function(nums) {
    let i=0, j=nums.length-1;
    const originals = [];
    while(i<=j) {
        const absFront = Math.abs(nums[i]);
        const absBack = Math.abs(nums[j]);
        if(absFront > absBack || absFront === absBack) {
            originals.push(nums[i]); // When abs values are matching we push the smaller `-ve` versions first so that the final array is sorted
            i++;
        } else {
            originals.push(nums[j]);
            j--;
        }
    }
    return originals.reverse();
};
```

FollowUp:
Idea is to split the array up in 2 parts and the breaking point will be first `+ve` number in the array. -> log(n)
Once splitting is complete, we can iterate backwards in the first part and forward in second part while comparing the absolute values. Once we've exhausted `k` numbers the last one was our answer. -> O(k)
T: O(logN + k)
Here is the JS code -
```
function kthSmallestSquare(nums, k) {
    const firstNonNegative = searchFirstNonNegative(nums);
    let negPointer = firstNonNegative - 1; // Last negative index
    let posPointer = firstNonNegative;    // First non-negative index
    let kthSmallest = null;
    while (k > 0) {
        if (negPointer >= 0 && (posPointer >= nums.length || Math.abs(nums[negPointer]) <= Math.abs(nums[posPointer]))) {
            if(k === 1) kthSmallest = nums[negPointer];
            negPointer--; // Take square from the negative side
        } else {
            if(k === 1) kthSmallest = nums[posPointer];
            posPointer++; // Take square from the positive side
        }
        k--;
    }
    return Math.pow(kthSmallest, 2);
}

function searchFirstNonNegative(nums) {
    let low = 0, high = nums.length - 1, firstNonNegative = nums.length;
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (nums[mid] >= 0) {
            firstNonNegative = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return firstNonNegative;
}

// Test Case -------------------------------
const nums = [-7, -2, -1, -1, 1, 2, 2, 2, 3, 5];
const k = 5;
console.log(kthSmallestSquare(nums, k)); // Output: 4
```
